// Render the ChainCompiler roadmap + changelog dynamically from data.json.
// data.json is regenerated by scripts/update_site.py from roadmap.json + the README changelog.
const STATUS_LABEL = { done: "✓ done", in_progress: "▸ in progress", planned: "○ planned" };

function el(tag, cls, html) {
  const e = document.createElement(tag);
  if (cls) e.className = cls;
  if (html != null) e.innerHTML = html;
  return e;
}

function renderRoadmap(phases) {
  const root = document.getElementById("roadmap");
  if (!root) return;
  root.innerHTML = "";
  for (const p of phases) {
    const card = el("div", `card s-${p.status}`);
    card.appendChild(el("span", "pill", STATUS_LABEL[p.status] || p.status));
    card.appendChild(el("div", "pid", p.id));
    card.appendChild(el("h3", null, p.title));
    card.appendChild(el("p", "blurb", p.blurb));
    const ul = el("ul");
    for (const it of p.items) ul.appendChild(el("li", null, it));
    card.appendChild(ul);
    root.appendChild(card);
  }
}

function renderChangelog(entries) {
  const root = document.getElementById("changelog");
  if (!root) return;
  root.innerHTML = "";
  if (!entries || !entries.length) { root.appendChild(el("p", "blurb", "No entries yet.")); return; }
  for (const e of entries) {
    const box = el("div", "entry");
    box.appendChild(el("div", null, `<span class="ver">${e.version}</span><span class="date">${e.date}</span>`));
    const ul = el("ul");
    for (const c of e.changes) ul.appendChild(el("li", null, c));
    box.appendChild(ul);
    root.appendChild(box);
  }
}

function setText(id, text) {
  const e = document.getElementById(id);
  if (e) e.textContent = text;
}

async function main() {
  try {
    const data = await (await fetch("data.json", { cache: "no-store" })).json();
    setText("project", data.project);
    setText("tagline", data.tagline || "");
    setText("updated", data.updated ? `updated ${data.updated}` : "");
    renderRoadmap(data.phases || []);
    renderChangelog(data.changelog || []);
  } catch (err) {
    const root = document.getElementById("roadmap");
    if (root) root.innerHTML =
      `<p class="blurb">Could not load <code>data.json</code> — run <code>python3 scripts/update_site.py</code>. (${err})</p>`;
  }
}
main();
